static inline at::Tensor empty_output_like_conv2d(const at::Tensor& x, const at::Tensor& w)
{
    // x: [N, Ci, Hi, Wi], w: [Co, Ci, Kh, Kw], stride=1, pad=0, dilation=1
    const auto N = x.size(0);
    const auto Co = w.size(0);
    const auto Hi = x.size(2);
    const auto Wi = x.size(3);
    const auto Kh = w.size(2);
    const auto Kw = w.size(3);
    const auto Ho = Hi - Kh + 1;
    const auto Wo = Wi - Kw + 1;
    return at::empty({N, Co, Ho, Wo}, x.options());
